#include<bits/stdc++.h>
#define LL long long
using namespace std;
LL A,B,C,D,p,q;
void solve(LL a,LL b,LL c,LL d){
    if(a<b&&c>d){p=1,q=1;return;}
    else{
        swap(p,q);solve(d%c,c,b-(d/c)*a,a);
        swap(p,q);q+=(d/c)*p;return;
    }
}
int main(){
    while(cin>>A>>B>>C>>D){p=0,q=0;solve(A,B,C,D);cout<<p<<"/"<<q<<"\n";}
    return 0;
}
